const { ApolloServer, gql } = require('apollo-server');

// Sample data for invoices
const invoices = [
  { id: '1', userId: 'user1', amount: 100, description: 'Invoice 1' },
  { id: '2', userId: 'user2', amount: 200, description: 'Invoice 2' },
];

// Type definitions
const typeDefs = gql`
  type Invoice {
    id: ID!
    userId: String!
    amount: Float!
    description: String!
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

// Resolvers
const resolvers = {
  Query: {
    invoice: (parent, { id }, context) => {
      // Assuming context.user contains the authenticated user
      const userId = context.user.id;
      const invoice = invoices.find(inv => inv.id === id);

      // Check if the invoice exists and belongs to the user
      if (invoice && invoice.userId === userId) {
        return invoice;
      }
      throw new Error('Invoice not found or access denied');
    },
  },
};

// Apollo Server setup
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Assuming authentication middleware sets req.user
    return { user: req.user };
  },
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});

